"use client";

import { useState, useEffect, useCallback } from "react";

type OrderItem = { id: number; product_name: string; quantity: number; price: number; category: string };
type Order = { id: number; user_name: string; flat_no: string; status: string; payment_method: string; total: number; created_at: string; items: OrderItem[] };

const statusColors: Record<string, string> = {
  pending: "bg-yellow-100 text-yellow-800",
  confirmed: "bg-blue-100 text-blue-800",
  ready: "bg-purple-100 text-purple-800",
  delivered: "bg-[#eef1ff] text-[var(--c-emerald)]",
  cancelled: "bg-red-100 text-red-800",
};
const nextStatus: Record<string, string> = { pending: "confirmed", confirmed: "ready", ready: "delivered" };
const statusAction: Record<string, string> = { pending: "Confirm", confirmed: "Mark Ready", ready: "Mark Delivered" };

export default function AdminOrdersPage() {
  const [orders, setOrders] = useState<Order[]>([]);
  const [filter, setFilter] = useState("pending");

  const fetchOrders = useCallback(() => {
    fetch(filter ? `/api/orders?status=${filter}` : "/api/orders").then(r => r.json()).then(setOrders);
  }, [filter]);

  useEffect(() => { fetchOrders(); const i = setInterval(fetchOrders, 10000); return () => clearInterval(i); }, [fetchOrders]);

  async function updateStatus(id: number, status: string) {
    await fetch(`/api/orders/${id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ status }) });
    fetchOrders();
  }

  return (
    <div>
      <div className="flex gap-2 mb-6 overflow-x-auto">
        {["pending", "confirmed", "ready", "delivered", "cancelled", ""].map(s => (
          <button key={s} onClick={() => setFilter(s)} className={`pill ${filter === s ? "pill-active" : "pill-inactive"}`}>{s || "All"}</button>
        ))}
      </div>

      {orders.length === 0 && <div className="text-center text-gray-400 py-12">No orders</div>}

      <div className="space-y-4">
        {orders.map(order => (
          <div key={order.id} className="card overflow-hidden animate-in">
            <div className="p-4 flex items-start justify-between">
              <div>
                <div className="flex items-center gap-2">
                  <span className="font-bold text-gray-800">#{order.id}</span>
                  <span className={`badge ${statusColors[order.status]}`}>{order.status}</span>
                  <span className={`badge ${order.payment_method === "tab" ? "bg-orange-100 text-orange-700" : "bg-gray-100 text-gray-600"}`}>
                    {order.payment_method === "tab" ? "Monthly Tab" : "COD"}
                  </span>
                </div>
                <div className="text-sm text-gray-500 mt-1">{order.user_name} - {order.flat_no}</div>
                <div className="text-xs text-gray-400 mt-0.5">{new Date(order.created_at).toLocaleString()}</div>
              </div>
              <div className="text-lg font-bold text-gray-800">&#8377;{order.total}</div>
            </div>
            <div className="px-4 py-2 border-t border-gray-50">
              {order.items.map(item => (
                <div key={item.id} className="flex justify-between py-1 text-sm">
                  <span className="text-gray-700">{item.product_name} x{item.quantity}</span>
                  <span className="text-gray-500">&#8377;{item.price * item.quantity}</span>
                </div>
              ))}
            </div>
            {nextStatus[order.status] && (
              <div className="px-4 py-3 bg-gray-50 flex gap-2">
                <button onClick={() => updateStatus(order.id, nextStatus[order.status])} className="btn btn-primary flex-1 py-2.5">{statusAction[order.status]}</button>
                {order.status === "pending" && (
                  <button onClick={() => updateStatus(order.id, "cancelled")} className="btn btn-danger px-4 py-2.5">Cancel</button>
                )}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
